B.apT=new A.bk(0,B.aQ,"A Pawn is Worth a Thousand Generals","Ippu Atai Senkin",B.a19)
B.aj7=new A.e("When your opponent attacks with a promoted Rook, remember that a Pawn-anchored Gold makes a solid guard.")
B.O0=new A.q("ln1g5/1ks6/1pp6/pl1p5/9/P1P6/1P1PSP3/2KGG4/LN6+r b Pp","Diagram 1-1")
B.ahi=new A.e("Diagram 1-1 shows where White has just dropped a Lance on 8d. Together with the promoted Rook on the bottom row, White aims to attack your King directly. The expected line of moves is:")
