B.apR=new A.bk(1,B.aQ,"A Pawn-anchored Gold is more solid than a rock","Kinzoko no Fu iwa yori katashi",B.Xs)
B.am9=new A.e("The Lance dropped on the first rank has eight squares to go to. If dropped on the second rank, it can only go to one square. When in doubt, drop the lance as far back as you can.")
