B.apE=new A.bk(25,B.bF,"Make a Vanguard Pawn, then Make it Stick","Kurai wo tottara kurai no kakuho",B.a3P)
B.af2=new A.e("People used to take this proverb quite seriously, and did the best they could to prevent the opponent from maintaining a 5e vanguard Pawn. But in present-day shogi, it does not always hold true.")
B.afQ=new A.e("Diagram 1 (last move K4a) shows where White has successfully realized the 5e vanguard Pawn. The position is supposed to be in favor of White according to the proverb, but not so in reality.")
B.Mh=new A.q("ln1g1k1nl/4r1gb1/p1pp1s1p1/4spp1p/4p4/P1P2PPRP/1P1PPSN2/1BKGSG3/LN6L b Pp","Diagram 1")
B.ah2=new A.e("See how Black's R,B,S,and N are ideally placed for an attack.")
B.Wy=A.a(s(["P3e","Px3e","P4e","Px4e","P5f","Px5f"]),t.s)
B.ab_=new A.Q(null,B.Wy,B.l)
B.aiv=new A.e("First he plays P3e before moving the Knight, and then P5f, thereby aiming at the Pawn on 5e. These are orthodox and effective moves on Black's part.")
